<script setup lang="ts">import{onMounted,ref}from'vue';import{useSessionsStore}from'../stores/sessions';const props=defineProps<{projectId:string}>(),store=useSessionsStore(),title=ref(''),summary=ref('');onMounted(()=>store.load(props.projectId));async function create(){if(!title.value.trim())return;await store.create(props.projectId,title.value,summary.value);title.value='';summary.value=''}function remove(id:string){if(window.confirm('Delete this session and unlink its memories?'))void store.remove(props.projectId,id)}</script>
<template><section class="phase-panel"><div class="tab-heading"><div><p class="eyebrow">Work log</p><h2>Development Sessions</h2></div></div><div v-if="store.error" class="alert error-alert">{{store.error}}</div><form v-if="!store.active" class="inline-form" @submit.prevent="create"><input v-model="title" maxlength="200" placeholder="Session title" required><input v-model="summary" placeholder="Optional summary"><button class="button primary">Start Session</button></form><article v-for="s in store.items" :key="s.id" class="memory-card"><div><span class="record-type">{{s.status}}</span><h3>{{s.title}}</h3><p>{{s.summary}}</p><small>{{new Date(s.startedAt).toLocaleString()}} · {{s.branchName||'No branch'}} · {{s.durationMinutes??0}} min</small></div><div class="record-actions"><button v-if="s.status==='ACTIVE'" @click="store.action(projectId,s.id,'pause')">Pause</button><button v-if="s.status==='PAUSED'" @click="store.action(projectId,s.id,'resume')">Resume</button><button v-if="s.status!=='COMPLETED'" @click="store.action(projectId,s.id,'complete')">Complete</button><button @click="remove(s.id)">Delete</button></div></article></section></template>
